// SPDX-License-Identifier: MIT
pragma solidity >=0.8.12 <0.9.0;
import "../openzeppelin-contracts/contracts/token/ERC20/ERC20.sol";
import "../openzeppelin-contracts/contracts/access/Ownable.sol";
import "../openzeppelin-contracts/contracts/token/ERC20/extensions/ERC20Permit.sol";

contract Scoin is ERC20, ERC20Permit, Ownable {
    // Define a state variable for the initial supply
    uint256 public INITIAL_SUPPLY;

    // Define struct for reward tiers
    struct RewardTier {
        uint256 minLikes;
        uint256 rewardAmount;
    }

    // Define struct for user data
    struct UserData {
        uint256 likeCount;
        uint256 moderationScore; // scaled by 1e18
        uint256 firstLikeTimestamp;
        uint8 rewardClaimedLevel; // The highest reward level claimed
    }

    // Map user addresses to their data
    mapping(address => UserData) public userData;
    // Array of reward tiers
    RewardTier[] public rewardTiers;

    // The single constructor for the contract
    constructor() ERC20("Scoin", "SCN") ERC20Permit("Scoin") Ownable(msg.sender) {
        // Set the initial supply
        INITIAL_SUPPLY = 1_000_000 * 1e18;
        // Mint the entire initial supply to the contract deployer
        _mint(msg.sender, INITIAL_SUPPLY);

        // Initialize reward tiers
        // Use the now-initialized INITIAL_SUPPLY
        rewardTiers.push(RewardTier(1000, (INITIAL_SUPPLY * 1) / 100));     // 1%
        rewardTiers.push(RewardTier(5000, (INITIAL_SUPPLY * 2) / 100));     // 2%
        rewardTiers.push(RewardTier(10000, (INITIAL_SUPPLY * 3) / 100));    // 3%
    }

    /**
     * @dev Records a like for a specific user. Only the owner can call this.
     * @param user The address of the user receiving the like.
     */
    function recordLike(address user) external onlyOwner {
        UserData storage data = userData[user];
        if (data.likeCount == 0) {
            data.firstLikeTimestamp = block.timestamp;
        }
        data.likeCount += 1;
    }

    /**
     * @dev Updates a user's moderation score. Only the owner can call this.
     * @param user The address of the user whose score to update.
     * @param score The new moderation score (scaled by 1e18, e.g., 0.5 * 1e18 for 0.5).
     */
    function updateModerationScore(address user, uint256 score) external onlyOwner {
        require(score <= 1e18, "Score out of range"); // Score cannot exceed 1e18 (equivalent to 1.0)
        userData[user].moderationScore = score;
    }

    /**
     * @dev Allows a user to claim their reward if they meet the criteria.
     */
    function claimReward() external {
        UserData storage data = userData[msg.sender];

        // Check if the user has already claimed any reward level
        require(data.rewardClaimedLevel == 0, "Already claimed a reward level");
        // Check moderation score
        require(data.moderationScore >= 0.5 * 1e18, "Moderation score too low");
        // Check claim period (within 30 days of the first like)
        require(block.timestamp <= data.firstLikeTimestamp + 30 days, "Claim period expired");

        uint8 level = 0;
        uint256 rewardAmount = 0;

        // Iterate through reward tiers from highest to lowest
        for (uint8 i = uint8(rewardTiers.length); i > 0; i--) {
            if (data.likeCount >= rewardTiers[i - 1].minLikes) {
                level = i;
                rewardAmount = rewardTiers[i - 1].rewardAmount;
                break; // Found the highest eligible level, exit loop
            }
        }

        require(level > 0, "Not enough likes for any reward");

        // Set the claimed level for the user
        data.rewardClaimedLevel = level;
        // Transfer the reward from the contract to the user
        // Note: The contract itself needs to hold enough Scoin tokens for this to work.
        // If you intended to mint tokens, you would need a _mint function (if available in ERC20 or a custom mechanism).
        // For this example, we assume the contract has the tokens.
        _transfer(address(this), msg.sender, rewardAmount);
        // This replaces _transfer(owner(), msg.sender, rewardAmount);
        // Because owner() is just the contract's owner, not necessarily where the tokens for distribution are held.
        // If tokens are held by the contract itself, we transfer from the contract's address.
    }

    /**
     * @dev Returns the claimable reward level and amount for a user.
     * @param user The address of the user.
     * @return level The claimable reward level (0 if none).
     * @return amount The amount of reward tokens.
     */

    function getClaimableLevel(address user) external view returns (uint8 level, uint256 amount) {
        UserData memory data = userData[user];

        // Check conditions for claiming a reward
        if (
            data.rewardClaimedLevel != 0 || // Already claimed a reward
            data.moderationScore < 0.5 * 1e18 || // Moderation score too low
            block.timestamp > data.firstLikeTimestamp + 30 days // Claim period expired
        ) {
            return (0, 0); // Not eligible
        }

        // Find the highest reward level the user is eligible for
        for (uint8 i = uint8(rewardTiers.length); i > 0; i--) {
            if (data.likeCount >= rewardTiers[i - 1].minLikes) {
                return (i, rewardTiers[i - 1].rewardAmount);
            }
        }

        return (0, 0); // Not enough likes for any level
    }
}

contracts/Smartwallet.sol.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.24;


import "../openzeppelin-contracts/contracts/access/Ownable.sol";
import "../openzeppelin-contracts/contracts/utils/cryptography/ECDSA.sol";
import "../openzeppelin-contracts/contracts/token/ERC20/utils/SafeERC20.sol";
import "../openzeppelin-contracts/contracts/interfaces/IERC20.sol";
import "../openzeppelin-contracts/contracts/utils/Address.sol";

import "../external/IAccount.sol";
import "../external/IEntryPoint.sol";
import {UserOperation} from "../external/UserOperation.sol";


/// @notice Smart contract wallet compatible with ERC-4337
// Wallet features:
// 1. Updateable entrypoint
// 2. Nonce for replay detection
// 3. ECDSA for signature validation
// In this early version, there is an owner/admin who is able to sweep the wallet in case of emergency
// Owner is default set to the deployer address
contract SmartWallet is Ownable, IAccount {
    event UpdateEntryPoint(address indexed _newEntryPoint, address indexed _oldEntryPoint);
    event WithdrawERC20(address indexed _to, address _token, uint256 _amount);
    event PayPrefund(address indexed _payee, uint256 _amount);

    /// @notice EntryPoint contract in the ERC-4337 architecture
    IEntryPoint public entryPoint;

    /// @notice Nonce used for replay protection
    uint256 public nonce;

    /// @notice Validate that only the entryPoint is able to call a method
    modifier onlyEntryPoint() {
        require(msg.sender == address(entryPoint), "SmartWallet: Only entryPoint can call this method");
        _;
    }

    /// @notice Able to receive ETH
    receive() external payable {}

    constructor(address _entryPoint, address _owner) Ownable(msg.sender) {
        entryPoint = IEntryPoint(_entryPoint);
        transferOwnership(_owner);
    }

    /// @notice Set the entrypoint contract, restricted to onlyOwner
    function setEntryPoint(address _newEntryPoint) external onlyOwner {
        emit UpdateEntryPoint(_newEntryPoint, address(entryPoint));
        entryPoint = IEntryPoint(_newEntryPoint);
    }

    /// @notice Validate that the userOperation is valid. Requirements:
    // 1. Only calleable by EntryPoint
    // 2. Signature is that of the contract owner
    // 3. Nonce is correct
    
    function validateUserOp(
        UserOperation calldata userOp,
        bytes32 userOpHash, // TODO: Shouldn't this hash be constructed internally over the userOp? Why is it passed?
        address /*aggregator*/,
        uint256 missingWalletFunds
    ) external override onlyEntryPoint returns (uint256 deadline) {
        // Validate signature
        _validateSignature(userOp, userOpHash);

        // TODO: Verify this is correct
        // UserOp may have initCode to deploy a wallet, in which case do not validate the nonce. Used in accountCreation
        if (userOp.initCode.length == 0) {
            // Validate nonce is correct - protect against replay attacks
            uint256 currentNonce = nonce;
            require(currentNonce == userOp.nonce, "SmartWallet: Invalid nonce");

            // Effects
            // Increment nonce
            _updateNonce();
        }

        // Interactions
        _prefundEntryPoint(missingWalletFunds);
        return 0;
    }

    /// @notice Method called by entryPoint to execute the calldata supplied by a wallet
    // TODO: Add a batch execute method?
    /// @param target - Address to send calldata payload for execution
    /// @param value - Amount of ETH to forward to target
    /// @param payload - Calldata to send to target for execution
    function executeFromEntryPoint(address target, uint256 value, bytes calldata payload) external onlyEntryPoint {
    (bool success,) = payable(target).call{value: value}(payload);
    Address.verifyCallResult(success, msg.data); // Use the built-in error handling in OpenZeppelin's Address library.
    }

    /// EMERGENCY RECOVERY
    /// @notice Withdraw ERC20 tokens from the wallet. Permissioned to only the owner
    function withdrawERC20(address token, address to, uint256 amount) external onlyOwner {
        SafeERC20.safeTransfer(IERC20(token), to, amount);
        emit WithdrawERC20(to, token, amount);
    }

    /// @notice Withdraw ETH from the wallet. Permissioned to only the owner
    function withdrawETH() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    /////////////////  INTERNAL METHODS ///////////////

    /// @notice Validate the signature of the userOperation
    function _validateSignature(UserOperation calldata userOp, bytes32 userOpHash) internal view {
        bytes32 messageHash = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", userOpHash));
        address signer = ECDSA.recover(messageHash, userOp.signature);
        require(signer == owner(), "SmartWallet: Invalid signature");
    }

    /// @notice Pay the EntryPoint in ETH ahead of time for the transaction that it will execute
    ///         Amount to pay may be zero, if the entryPoint has sufficient funds or if a paymaster is used
    ///         to pay the entryPoint through other means
    /// @param amount - Amount of ETH to pay the entryPoint
    function _prefundEntryPoint(uint256 amount) internal onlyEntryPoint {
        if (amount == 0) {
            return;
        }

        (bool success,) = payable(address(entryPoint)).call{value: amount}("");
        require(success, "SmartWallet: ETH entrypoint payment failed");
        emit PayPrefund(address(this), amount);
    }

    /// @notice Update the nonce storage variable
    function _updateNonce() internal {
        nonce++;
    }
}

external/IAccount.sol.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.12;

import "./UserOperation.sol";

interface IAccount {
    /**
     * Validate user's signature and nonce
     * the entryPoint will make the call to the recipient only if this validation call returns successfully.
     *
     * @dev Must validate caller is the entryPoint.
     *      Must validate the signature and nonce
     * @param userOp the operation that is about to be executed.
     * @param userOpHash hash of the user's request data. can be used as the basis for signature.
     * @param aggregator the aggregator used to validate the signature. NULL for non-aggregated signature accounts.
     * @param missingAccountFunds missing funds on the account's deposit in the entrypoint.
     *      This is the minimum amount to transfer to the sender(entryPoint) to be able to make the call.
     *      The excess is left as a deposit in the entrypoint, for future calls.
     *      can be withdrawn anytime using "entryPoint.withdrawTo()"
     *      In case there is a paymaster in the request (or the current deposit is high enough), this value will be zero.
     * @return deadline the last block timestamp this operation is valid, or zero if it is valid indefinitely.
     *      Note that the validation code cannot use block.timestamp (or block.number) directly.
     */
    function validateUserOp(
        UserOperation calldata userOp,
        bytes32 userOpHash,
        address aggregator,
        uint256 missingAccountFunds
    ) external returns (uint256 deadline);
}

external/IAggregator.sol.content:
// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.12;

import "./UserOperation.sol";

/**
 * Aggregated Signatures validator.
 */
interface IAggregator {

    /**
     * validate aggregated signature.
     * revert if the aggregated signature does not match the given list of operations.
     */
    function validateSignatures(UserOperation[] calldata userOps, bytes calldata signature) external view;

    /**
     * validate signature of a single userOp
     * This method is called by EntryPoint.simulateUserOperation() if the account has an aggregator.
     * First it validates the signature over the userOp. then it return data to be used when creating the handleOps:
     * @param userOp the userOperation received from the user.
     * @return sigForUserOp the value to put into the signature field of the userOp when calling handleOps.
     *    (usually empty, unless account and aggregator support some kind of "multisig"
     */
    function validateUserOpSignature(UserOperation calldata userOp)
    external view returns (bytes memory sigForUserOp);

    /**
     * aggregate multiple signatures into a single value.
     * This method is called off-chain to calculate the signature to pass with handleOps()
     * bundler MAY use optimized custom code perform this aggregation
     * @param userOps array of UserOperations to collect the signatures from.
     * @return aggregatesSignature the aggregated signature
     */
    function aggregateSignatures(UserOperation[] calldata userOps) external view returns (bytes memory aggregatesSignature);
}

